 1	import * as React from 'react';
 2	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
 3	import {
 4	  PersistentVolumeClaimModel,
 5	  StorageClassModel,
 6	} from '@odf/shared/models';
 7	import { getPVCStatusGroups } from '@odf/shared/status/Inventory';
 8	import {
 9	  PersistentVolumeClaimKind,
10	  StorageClassResourceKind,
11	} from '@odf/shared/types';
12	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
13	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
14	import { ResourceInventoryItem } from '@openshift-console/dynamic-plugin-sdk-internal';
15	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
16	import { getStorageClassName } from '../../utils/common';
17	import { BlockPoolDashboardContext } from './block-pool-dashboard-context';
18	
19	export const scResource = {
20	  kind: StorageClassModel.kind,
21	  namespaced: false,
22	  isList: true,
23	};
24	
25	export const pvcResource = {
26	  isList: true,
27	  kind: PersistentVolumeClaimModel.kind,
28	};
29	
30	export const InventoryCard: React.FC = () => {
31	  const { t } = useCustomTranslation();
32	  const { obj } = React.useContext(BlockPoolDashboardContext);
33	  const { name } = obj.metadata;
34	
35	  const [scResources, scLoaded, scLoadError] =
36	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
37	  const [pvcResources, pvcLoaded, pvcLoadError] =
38	    useK8sWatchResource<PersistentVolumeClaimKind[]>(pvcResource);
39	  const scMemoized: StorageClassResourceKind[] = useDeepCompareMemoize(
40	    scResources,
41	    true
42	  );
43	  const pvcMemoized: PersistentVolumeClaimKind[] = useDeepCompareMemoize(
44	    pvcResources,
45	    true
46	  );
47	
48	  const poolSc: StorageClassResourceKind[] = React.useMemo(
49	    () =>
50	      scMemoized ? scMemoized.filter((sc) => sc.parameters?.pool === name) : [],
51	    [scMemoized, name]
52	  );
53	  const pvcs: PersistentVolumeClaimKind[] = React.useMemo(() => {
54	    const scList = poolSc.map((sc) => sc?.metadata.name);
55	    if (pvcLoaded && !pvcLoadError) {
56	      return pvcMemoized.filter((pvc) =>
57	        scList.includes(getStorageClassName(pvc))
58	      );
59	    } else return [];
60	  }, [poolSc, pvcMemoized, pvcLoaded, pvcLoadError]);
61	
62	  return (
63	    <Card data-test-id="inventory-card">
64	      <CardHeader>
65	        <CardTitle>{t('Inventory')}</CardTitle>
66	      </CardHeader>
67	      <CardBody>
68	        <ResourceInventoryItem
69	          dataTest="inventory-sc"
70	          isLoading={!scLoaded}
71	          error={!!scLoadError}
72	          kind={StorageClassModel as any}
73	          resources={poolSc}
74	          showLink
75	        />
76	        <ResourceInventoryItem
77	          dataTest="inventory-pvc"
78	          isLoading={!pvcLoaded}
79	          error={!!pvcLoadError}
80	          kind={PersistentVolumeClaimModel as any}
81	          resources={pvcs}
82	          mapper={getPVCStatusGroups}
83	          showLink
84	        />
85	      </CardBody>
86	    </Card>
87	  );
88	};

